import psycopg2
from psycopg2 import sql

def install_extension(db_connection, extension_name):
    try:
        with db_connection.cursor() as cursor:
            create_extension_query = sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(sql.Identifier(extension_name))
            cursor.execute(create_extension_query)
            db_connection.commit()
            print(f"Extension {extension_name} installed successfully.")
    except psycopg2.Error as e:
        print(f"Error installing extension {extension_name}: {e}")

def main():
    # Database connection parameters
    db_params = {
        'dbname': 'your_database',
        'user': 'your_username',
        'password': 'your_password',
        'host': 'localhost',
        'port': 5432
    }
    
    # Establish a database connection
    try:
        conn = psycopg2.connect(**db_params)
        
        while True:
            extension_name = input("Enter the name of the PostgreSQL extension to install (or 'exit' to quit): ").strip().lower()
            
            if extension_name == 'exit':
                break
            
            if not extension_name:
                print("Please enter a valid extension name.")
                continue
            
            install_extension(conn, extension_name)
    
    except psycopg2.Error as e:
        print(f"Database connection failed: {e}")
    finally:
        if conn:
            conn.close()

if __name__ == "__main__":
    main()